create table sessions (id text primary key, token_hash text not null, created_at timestamptz not null, expires_at timestamptz not null, revoked_at timestamptz);
create table safety_checks (id text primary key, session_id text not null references sessions(id), result jsonb not null, created_at timestamptz not null);
create table assessments (id text primary key, session_id text not null references sessions(id), safety_check_id text not null references safety_checks(id), status text not null, report_mode text, safety_route text, advisor_client_id text, consent_status text, created_at timestamptz not null, updated_at timestamptz not null, completed_at timestamptz);
create table assessment_sessions (id text primary key, assessment_id text not null references assessments(id), session_id text not null references sessions(id), source text not null, created_at timestamptz not null, unique (assessment_id, session_id));
create table assessment_answers (id text primary key, assessment_id text not null references assessments(id), question_id text not null, value jsonb not null, updated_at timestamptz not null, unique (assessment_id, question_id));
create table assessment_summaries (id text primary key, assessment_id text not null references assessments(id), checkpoint_id text not null, text text not null, confirmed_at timestamptz not null, unique (assessment_id, checkpoint_id));
create table report_snapshots (assessment_id text primary key references assessments(id), session_id text not null references sessions(id), report_mode text not null, safety_route text, initial_view jsonb not null, full_report jsonb, created_at timestamptz not null);
create table payments (id text primary key, session_id text not null references sessions(id), assessment_id text not null references assessments(id), product_code text not null, amount integer not null, status text not null, invoice_id text, sender_invoice_no text, expires_at timestamptz, paid_at timestamptz, created_at timestamptz not null, updated_at timestamptz not null);
create table entitlements (id text primary key, session_id text not null references sessions(id), assessment_id text not null references assessments(id), payment_id text not null references payments(id), product_code text not null, status text not null, granted_at timestamptz not null, unique (assessment_id, product_code));
create table recovery_contacts (id text primary key, contact_group_id text not null, session_id text not null references sessions(id), assessment_id text references assessments(id), payment_id text references payments(id), entitlement_id text references entitlements(id), type text not null, contact_hash text not null, encrypted_contact text not null, verified_at timestamptz, created_at timestamptz not null, updated_at timestamptz);
create table recovery_challenges (id text primary key, rate_key text not null, contact_id text references recovery_contacts(id), code_hash text not null, attempts integer not null, expires_at timestamptz not null, used_at timestamptz, created_at timestamptz not null);
create table advisor_accounts (id text primary key, email text not null unique, name text not null, password_hash text not null, status text not null, force_password_change boolean not null default true, created_at timestamptz not null);
create table advisor_sessions (id text primary key, advisor_id text not null references advisor_accounts(id), token_hash text not null, expires_at timestamptz not null, revoked_at timestamptz, created_at timestamptz not null);
create table advisor_clients (id text primary key, advisor_id text not null references advisor_accounts(id), assessment_id text references assessments(id), invite_hash text, invite_expires_at timestamptz, consent_status text, consent_version text, consent_at timestamptz, created_at timestamptz not null);
create table advisor_commissions (id text primary key, advisor_id text not null references advisor_accounts(id), payment_id text not null references payments(id), amount integer not null, status text not null, created_at timestamptz not null, unique (payment_id));
create table advisor_report_access_logs (id text primary key, advisor_id text not null references advisor_accounts(id), assessment_id text not null references assessments(id), allowed boolean not null, reason text not null, created_at timestamptz not null);
create table admin_audit_logs (id text primary key, admin_id text not null, action text not null, target_type text not null, target_id text not null, details jsonb not null, created_at timestamptz not null);
